gameActivityClassAdditions.insert:
// 갤러리 호출 인텐트 생성 및 실행
public void OpenAndroidGallery() {
android.content.Intent intent = new android.content.Intent(android.content.Intent.ACTION_PICK, android.provider.MediaStore.Images.Media.EXTERNAL_CONTENT_URI);
startActivityForResult(intent, 7777);
}

// C++에서 구현할 네이티브 함수 선언
public native void nativeOnImageSelected(String imagePath);

gameActivityOnActivityResultAdditions.insert:
if (requestCode == 7777 && resultCode == RESULT_OK && data != null) {
android.net.Uri selectedImage = data.getData();
if (selectedImage != null) {
// C++ 네이티브 함수로 선택된 이미지 URI 문자열 전달
nativeOnImageSelected(selectedImage.toString());
}
}
